import{_ as e,o as t,c as a,Q as i}from"./chunks/framework.c4d6cd72.js";const m=JSON.parse('{"title":"Tokenomics","description":"","frontmatter":{},"headers":[],"relativePath":"overview/tokenomics.md","filePath":"overview/tokenomics.md"}'),n={name:"overview/tokenomics.md"},o=i('<h1 id="tokenomics" tabindex="-1">Tokenomics <a class="header-anchor" href="#tokenomics" aria-label="Permalink to &quot;Tokenomics&quot;">​</a></h1><p>This topic provides a summary of the key financial concepts that are operational on the platform.</p><h2 id="payment-model" tabindex="-1">Payment model <a class="header-anchor" href="#payment-model" aria-label="Permalink to &quot;Payment model&quot;">​</a></h2><p>The FIB provides a freemium pay-per-use model that allows users to earn and spend internal digital credits.</p><p>Credits can be spent on downloading fraud event data from other users.</p><h2 id="uploading-fraud-events" tabindex="-1">Uploading fraud events <a class="header-anchor" href="#uploading-fraud-events" aria-label="Permalink to &quot;Uploading fraud events&quot;">​</a></h2><p>In order to incentivize the registered peers to submit the fraud events that they have encountered, credits are rewarded for every submitted contribution.</p><p>See the following related tutorials:</p><ul><li><a href="./../tutorials-web/uploading-fraud-data.html">Tutorials: Web UI &gt; Uploading fraud data</a></li><li><a href="./../tutorials-api/submitting-a-contribution.html">Tutorials: API &gt; Submitting a contribution</a></li></ul><h2 id="downloading-fraud-events" tabindex="-1">Downloading fraud events <a class="header-anchor" href="#downloading-fraud-events" aria-label="Permalink to &quot;Downloading fraud events&quot;">​</a></h2><p>The earned credits can be used to pay for downloading the fraud event data stored on the blockchain, which enables peers to update their own records and stay informed about the latest fraudulent activities. This process helps organizations to remain vigilant and prevent fraudulent activities from occurring within their own system.</p><p>See the following related tutorials:</p><ul><li><a href="./../tutorials-web/downloading-fraud-data.html">Tutorials: Web UI &gt; Downloading fraud data</a></li><li><a href="./../tutorials-api/retrieving-top-contributions.html">Tutorials: API &gt; Retrieving top contributions</a></li></ul><h2 id="credit-balance" tabindex="-1">Credit balance <a class="header-anchor" href="#credit-balance" aria-label="Permalink to &quot;Credit balance&quot;">​</a></h2><p>The number of digital credits that a peer has on their account, and that can be used to pay for downloading of fraud event data.</p><p>A peer can check their current credit balance by going to the <a href="./web-interface.html#tokens">Tokens</a> page of the FIB Web UI or by calling the following API endpoint: <a href="./../api-specification/wallet-controller/retrieving-credit-balance.html">Retrieving credit balance</a>.</p><h2 id="confidence-index" tabindex="-1">Confidence index <a class="header-anchor" href="#confidence-index" aria-label="Permalink to &quot;Confidence index&quot;">​</a></h2><p>All of the contributions submitted to the blockchain are automatically evaluated and assigned a score—<strong>confidence index</strong>—which is a numeric representation of the level of certainty that a contribution is fraudulent.</p><p>When assigning a contribution with a confidence index value, FIB considers many crucial factors, such as the presence of CLI manipulation, origination from a known hotspot of fraudulent activity, attack patterns, event confirmation by multiple peers, etc.</p><p>The confidence index value inherently affects the price of downloading the fraud event data. By default, peers download fraud event data in accordance with the <a href="#current-default-conversion-rate">default conversion rate</a>. However, when <a href="./../api-specification/contribution-controller/retrieving-top-contributions.html">retrieving contributions</a> (see the <code>confidence-score</code> parameter) a peer can specify whether they want the price of the retrieved contributions to be calculated in accordance with the confidence index. If enabled, the price of any given contribution is expected to rise above the <a href="#current-default-conversion-rate">default conversion rate</a>.</p><div class="tip custom-block"><p class="custom-block-title">Info</p><p>As new fraud event data is uploaded to the blockchain, the confidence index value for any given contribution is constantly updated.</p></div><h2 id="current-default-conversion-rate" tabindex="-1">Current default conversion rate <a class="header-anchor" href="#current-default-conversion-rate" aria-label="Permalink to &quot;Current default conversion rate&quot;">​</a></h2><ul><li><strong>Uploading fraud events</strong>: <code>10</code> credits per <code>id</code> fraud identifier.</li><li><strong>Downloading fraud events</strong>: <code>1</code> credit per <code>id</code> fraud identifier.</li></ul><h2 id="welcome-bonus" tabindex="-1">Welcome bonus <a class="header-anchor" href="#welcome-bonus" aria-label="Permalink to &quot;Welcome bonus&quot;">​</a></h2><p>Every new peer that has successfully registered with FIB, automatically receives a <code>1,000</code> credits bonus.</p><h2 id="premium-subscription" tabindex="-1">Premium subscription <a class="header-anchor" href="#premium-subscription" aria-label="Permalink to &quot;Premium subscription&quot;">​</a></h2><p>Our premium subscription offers custom paid conditions for users seeking to gain access to exclusive features and benefits, tailored to their individual needs.</p><p>To apply for a premium subscription and discuss the conditions, go to the <a href="./web-interface.html#profile">Profile</a> page of the FIB Web UI and select <strong>Request</strong> on the <strong>Subscription</strong> tab.</p><p>Alternatively, you may contact us at <a href="mailto:support@fraudintelligencelimited.com" target="_blank" rel="noreferrer">support@fraudintelligencelimited.com</a>.</p><h2 id="monthly-reward-limit" tabindex="-1">Monthly reward limit <a class="header-anchor" href="#monthly-reward-limit" aria-label="Permalink to &quot;Monthly reward limit&quot;">​</a></h2><p>The monthly reward limit is currently <code>1,000,000,000</code> rewards per peer.</p><p>A peer can check their current limit status by calling the following API endpoint: <a href="./../api-specification/peer-controller/retrieving-peer-limit-status.html">Retrieving peer limit status</a>.</p><div class="tip custom-block"><p class="custom-block-title">Info</p><p><em>Fraud Intelligence Limited</em> may from time to time, by an in-advance written email notice to you, adjust the reward limit, in accordance with the <a href="https://github.com/fraud-intelligence-limited/fil-legal/blob/main/Fraud%20Intelligence%20Blockchain%20Terms%20of%20Use%20v4.0.pdf" target="_blank" rel="noreferrer">Fraud Intelligence Blockchain Terms &amp; Conditions document</a>.</p></div>',33),r=[o];function c(l,d,s,u,h,p){return t(),a("div",null,r)}const b=e(n,[["render",c]]);export{m as __pageData,b as default};
